  warshipProg=0
  backSoundLoop=0
  firePillarX=0
}
else if room=rLowFacCutA
{
  fadeColor=c_black
  fadeAlpha=1
  oPlayer1.visible=0
  musicFade=global.optMusic*100
  fadeAmt=10
  backSoundLoop=0
}
